 1	import NetworkAttachmentDefinitionModel from '@kubevirt-ui/kubevirt-api/console/models/NetworkAttachmentDefinitionModel';
 2	import { NADListPermissionsMap } from '@kubevirt-utils/components/NetworkInterfaceModal/components/hooks/types';
 3	import {
 4	  DEFAULT_NAMESPACE,
 5	  OPENSHIFT_MULTUS_NS,
 6	  OPENSHIFT_SRIOV_NETWORK_OPERATOR_NS,
 7	} from '@kubevirt-utils/constants/constants';
 8	import { K8sVerb, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 9	
10	type UseNADListPermissions = () => NADListPermissionsMap;
11	
12	const useNADListPermissions: UseNADListPermissions = () => {
13	  const [canListDefaultNSNads] = useAccessReview({
14	    group: NetworkAttachmentDefinitionModel.apiGroup,
15	    namespace: DEFAULT_NAMESPACE,
16	    resource: NetworkAttachmentDefinitionModel.plural,
17	    verb: 'list' as K8sVerb,
18	  });
19	
20	  const [canListOpenShiftSRIOVNetworkOperatorNamespaceNADs] = useAccessReview({
21	    group: NetworkAttachmentDefinitionModel.apiGroup,
22	    namespace: OPENSHIFT_SRIOV_NETWORK_OPERATOR_NS,
23	    resource: NetworkAttachmentDefinitionModel.plural,
24	    verb: 'list' as K8sVerb,
25	  });
26	
27	  const [canListOpenShiftMultusNamespaceNADs] = useAccessReview({
28	    group: NetworkAttachmentDefinitionModel.apiGroup,
29	    namespace: OPENSHIFT_MULTUS_NS,
30	    resource: NetworkAttachmentDefinitionModel.plural,
31	    verb: 'list' as K8sVerb,
32	  });
33	
34	  return {
35	    default: canListDefaultNSNads,
36	    OPENSHIFT_MULTUS_NS: canListOpenShiftMultusNamespaceNADs,
37	    OPENSHIFT_SRIOV_NETWORK_OPERATOR_NS: canListOpenShiftSRIOVNetworkOperatorNamespaceNADs,
38	  };
39	};
40	
41	export default useNADListPermissions;

